# ── GitHub 자동 저장 ─────────────────────────────────
_MARKER_END = "    'learned_nontax_reason': [],"

def _github_save_config(new_cfg):
    if not _HAS_REQ:
        return False, "requests 없음"
    try:
        token = st.secrets.get("GITHUB_TOKEN", "")
        repo  = st.secrets.get("GITHUB_REPO", "")
        fpath = st.secrets.get("GITHUB_FILE", "app.py")
        if not token or not repo:
            return False, "Secrets 미설정"
        headers = {"Authorization": "token " + token, "Accept": "application/vnd.github.v3+json"}
        url = "https://api.github.com/repos/" + repo + "/contents/" + fpath
        r = _req.get(url, headers=headers)
        if r.status_code != 200:
            return False, "파일 조회 실패"
        sha = r.json()["sha"]
        current = base64.b64decode(r.json()["content"]).decode("utf-8")
        s = current.find("DEFAULT_CONFIG = {")
        e = current.find(_MARKER_END)
        if s < 0 or e < 0:
            return False, "CONFIG 마커 없음"
        e = current.find("\n}", e) + 2
        parts = ["DEFAULT_CONFIG = {\n"]
        for k, v in new_cfg.items():
            parts.append("    " + repr(k) + ": " + repr(v) + ",\n")
        parts.append("}")
        updated = current[:s] + "".join(parts) + current[e:]
        encoded = base64.b64encode(updated.encode("utf-8")).decode("utf-8")
        r2 = _req.put(url, headers=headers, json={"message": "설정 자동 업데이트", "content": encoded, "sha": sha})
        if r2.status_code in [200, 201]:
            return True, "저장 완료"
        return False, "저장 실패 " + str(r2.status_code)
    except Exception as ex:
        return False, str(ex)

